#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=200005;
int n,m,d,f[N],ru[N],cnt[N],siz[N],vis[N];
vector<int> g[N];
int find(int x)
{
	if(x==f[x]) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m>>d;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
		ru[u]++,ru[v]++;
	}
	queue<int> q;
	for(int i=1;i<=n;i++)
	{
		if(ru[i]<d)
		{
			q.push(i);
			vis[i]=1;
		}
	}
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i];
			ru[v]--;
			if(ru[v]<d&&!vis[v])
			{
				q.push(v);
				vis[v]=1;
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		f[i]=i;
	}
	for(int i=1;i<=n;i++)
	{
		if(ru[i]<d) continue;
		for(int j=0;j<g[i].size();j++)
		{
			int v=g[i][j];
			if(ru[v]<d) continue;
			int fu=find(i),fv=find(v);
			f[fu]=fv;
		}
	}
	for(int i=1;i<=n;i++)
	{
		siz[find(i)]++;
	}
	int mx=d,ans=0;
	for(int i=1;i<=n;i++)
	{
		if(siz[i]>mx)
		{
			mx=siz[i];
			ans=i;
		}
	}
	if(ans==0)
	{
		cout<<"NIE\n";
		return 0;
	}
	cout<<mx<<"\n";
	for(int i=1;i<=n;i++)
	{
		if(find(i)==ans) cout<<i<<" ";
	}
	return 0;
}
